function getPosterFig(key) {
  if (!key) return null;
  const k = key.toLowerCase().replace(/\s+/g, '-').replace(/[^a-z0-9-]/g, '');
  const img = POSTER_IMGS[k]
    || POSTER_IMGS[Object.keys(POSTER_IMGS).find(pk => k.includes(pk) || pk.includes(k))]
    || null;
  if (!img) return null;
  return `<img src="${img}" class="tech-fig" alt="">`;
}